/**
 * CRM consumer — projects merchant_customers from payment.recorded.
 *
 * Facts → projection (not transactions trigger). Claims make it idempotent.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import { resolveCheckoutMetadata } from './transactionLineItems.ts';

const NON_CRM_PURCHASE_TYPES = new Set([
  'domain',
  'domain_renewal',
  'plan_subscription',
  'product_subscription',
  'developer_api_subscription',
  'sponsored_listing',
  'agency',
  'studio_subscription',
  'bank_transfer',
]);

export async function consumeCrmFromPaymentRecorded(
  admin: SupabaseClient,
  input: {
    reference: string;
    merchantId: string;
    transactionId: string;
    buyerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    paymentSessionId?: string | null;
    businessIntent?: string | null;
    processingRail?: string | null;
    correlationId?: string | null;
    causationId?: string | null;
  },
): Promise<{ ok: boolean; skipped?: boolean; reason?: string }> {
  const reference = String(input.reference ?? '').trim();
  const buyerEmail = String(input.buyerEmail ?? '').trim().toLowerCase();
  if (!reference || !buyerEmail) {
    return { ok: true, skipped: true, reason: 'no_buyer_email' };
  }

  const meta = await resolveCheckoutMetadata(admin, {
    reference,
    paymentSessionId: input.paymentSessionId ?? null,
  });
  const purchaseType = String(meta.purchase_type ?? meta.object_type ?? '').toLowerCase();
  if (NON_CRM_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: true, skipped: true, reason: 'non_crm_purchase' };
  }

  // Projection first: merchant_customers is rebuilt from facts, not the trigger.
  const { data: projected, error: projErr } = await admin.rpc(
    'project_merchant_customer_from_payment',
    { p_reference: reference },
  );
  if (projErr) {
    console.error('project_merchant_customer_from_payment', reference, projErr.message);
    return { ok: false, reason: projErr.message };
  }
  const proj = (projected ?? {}) as { ok?: boolean; projected?: boolean; customer_id?: string };

  const { data: lineItems } = await admin
    .from('transaction_line_items')
    .select('product_id, name, quantity, line_total')
    .eq('transaction_id', input.transactionId)
    .order('sort_order');

  const productSummary = (lineItems ?? [])
    .filter((l) => l.product_id)
    .map((l) => ({
      product_id: l.product_id,
      name: l.name,
      quantity: l.quantity,
      line_total: l.line_total,
    }));

  const { count: priorCount } = await admin
    .from('transactions')
    .select('id', { count: 'exact', head: true })
    .eq('merchant_id', input.merchantId)
    .eq('status', 'success')
    .ilike('buyer_email', buyerEmail)
    .neq('id', input.transactionId)
    .gte('created_at', new Date(Date.now() - 365 * 86400000).toISOString());

  const envelopeMeta = {
    correlation_id: input.correlationId ?? null,
    causation_id: input.causationId ?? null,
  };

  await emitMerchantBusinessEvent(admin, {
    merchantId: input.merchantId,
    eventType: 'customer_purchase_recorded',
    actorType: 'buyer',
    customerEmail: buyerEmail,
    reference,
    amount: input.amount ?? null,
    currency: input.currency ?? null,
    source: 'payment.recorded',
    idempotencyKey: `crm:purchase:${reference}`,
    payload: {
      ...envelopeMeta,
      fact_type: 'customer.purchase_recorded',
      transaction_id: input.transactionId,
      customer_id: proj.customer_id ?? null,
      business_intent: input.businessIntent ?? null,
      processing_rail: input.processingRail ?? null,
      product_count: productSummary.length,
      products: productSummary.slice(0, 20),
      prior_purchases_12mo: priorCount ?? 0,
      projection_created: proj.projected === true,
    },
  });

  if ((priorCount ?? 0) > 0) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'customer_returned',
      actorType: 'buyer',
      customerEmail: buyerEmail,
      reference,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `crm:returned:${reference}`,
      payload: {
        ...envelopeMeta,
        fact_type: 'customer.returned',
        prior_purchases: priorCount,
        transaction_id: input.transactionId,
      },
    });
  }

  return { ok: true };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export function paystackWebhookEventKey(
  eventType: string,
  reference: string,
  data: Record<string, unknown>,
): string {
  const ref = reference || String(data.id ?? data.transaction_reference ?? '');
  if (ref) return `${eventType}:${ref}`;
  return `${eventType}:${crypto.randomUUID()}`;
}

/** Claim outcome — `error` means dedup could not be verified; caller must not process. */
export type WebhookClaimResult = 'claimed' | 'duplicate' | 'error';

export async function claimPaystackWebhook(
  admin: SupabaseClient,
  eventType: string,
  reference: string,
  data: Record<string, unknown>,
  rawPayload: unknown,
): Promise<WebhookClaimResult> {
  const eventKey = paystackWebhookEventKey(eventType, reference, data);
  const { data: claimed, error } = await admin.rpc('claim_platform_webhook_event', {
    p_event_key: eventKey,
    p_event_type: eventType,
    p_reference: reference || null,
    p_payload: rawPayload ?? {},
    p_provider: 'paystack',
  });
  if (error) {
    console.error('claim_platform_webhook_event', error.message);
    return 'error';
  }
  return claimed === false ? 'duplicate' : 'claimed';
}

/**
 * Record how webhook processing ended so every event is traceable
 * (admin reconciliation surfaces `failed` rows for replay).
 */
export async function markWebhookResult(
  admin: SupabaseClient,
  eventKey: string,
  status: 'processed' | 'failed',
  opts: { error?: string; startedAt?: number } = {},
): Promise<void> {
  const { error } = await admin.rpc('mark_platform_webhook_result', {
    p_event_key: eventKey,
    p_status: status,
    p_error: opts.error ?? null,
    p_ms: opts.startedAt ? Math.round(Date.now() - opts.startedAt) : null,
  });
  if (error) console.error('mark_platform_webhook_result', error.message);
}

export type AppendPaymentEventOpts = {
  eventType: string;
  reference?: string | null;
  idempotencyKey?: string | null;
  app?: string | null;
  merchantId?: string | null;
  userId?: string | null;
  amount?: number | null;
  currency?: string | null;
  payload?: Record<string, unknown>;
  correlationId?: string | null;
  causationId?: string | null;
  eventVersion?: number | null;
  producer?: string | null;
};

export async function appendPlatformPaymentEvent(
  admin: SupabaseClient,
  opts: AppendPaymentEventOpts,
): Promise<string | null> {
  const args: Record<string, unknown> = {
    p_event_type: opts.eventType,
    p_reference: opts.reference ?? null,
    p_idempotency_key: opts.idempotencyKey ?? null,
    p_app: opts.app ?? null,
    p_merchant_id: opts.merchantId ?? null,
    p_user_id: opts.userId ?? null,
    p_amount: opts.amount ?? null,
    p_currency: opts.currency ?? null,
    p_payload: opts.payload ?? {},
    p_correlation_id: opts.correlationId ?? null,
    p_causation_id: opts.causationId ?? null,
    p_event_version: opts.eventVersion ?? 1,
    p_producer: opts.producer ?? null,
  };
  const { data, error } = await admin.rpc('append_platform_payment_event', args);
  if (error) {
    // Older overload without envelope columns.
    const { data: legacy, error: legacyErr } = await admin.rpc('append_platform_payment_event', {
      p_event_type: opts.eventType,
      p_reference: opts.reference ?? null,
      p_idempotency_key: opts.idempotencyKey ?? null,
      p_app: opts.app ?? null,
      p_merchant_id: opts.merchantId ?? null,
      p_user_id: opts.userId ?? null,
      p_amount: opts.amount ?? null,
      p_currency: opts.currency ?? null,
      p_payload: {
        ...(opts.payload ?? {}),
        _envelope: {
          correlation_id: opts.correlationId ?? null,
          causation_id: opts.causationId ?? null,
          version: opts.eventVersion ?? 1,
          producer: opts.producer ?? null,
        },
      },
    });
    if (legacyErr) {
      console.error('append_platform_payment_event', opts.eventType, legacyErr.message);
      return null;
    }
    return typeof legacy === 'string' ? legacy : null;
  }
  return typeof data === 'string' ? data : null;
}

export function resolveAppFromMetadata(metadata: Record<string, unknown>): string | null {
  const agency = String(metadata.app ?? '').toLowerCase();
  if (agency === 'agency') return 'agency';
  const eco = String(metadata.ecosystem_app ?? '').toLowerCase();
  if (eco) return eco;
  const purchase = String(metadata.purchase_type ?? '').toLowerCase();
  if (purchase === 'plan_subscription') return 'pay';
  if (purchase === 'studio_subscription') return 'studio';
  if (agency === 'studio') return 'studio';
  return null;
}

/**
 * Inventory bounded context — consumes inventory.consume.requested.
 *
 * payment.recorded does not mutate stock directly. It requests consume;
 * this consumer claims, applies stock, and emits inventory.consumed.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import {
  finalizePaymentLineItems,
  isMarketplaceCheckout,
  shouldSkipInventoryForPayment,
} from './transactionLineItems.ts';

export type InventoryConsumeInput = {
  reference: string;
  merchantId: string;
  transactionId: string;
  buyerEmail?: string | null;
  amount?: number | null;
  currency?: string | null;
  paymentSessionId?: string | null;
  metadata: Record<string, unknown>;
  correlationId?: string | null;
  causationId?: string | null;
};

export async function consumeInventoryConsumeRequested(
  admin: SupabaseClient,
  input: InventoryConsumeInput,
): Promise<{ ok: boolean; skipped?: boolean; reason?: string; linesApplied?: number }> {
  const reference = String(input.reference ?? '').trim();
  if (!reference || !input.merchantId) {
    return { ok: false, reason: 'reference_and_merchant_required' };
  }

  if (shouldSkipInventoryForPayment(input.metadata)) {
    return { ok: true, skipped: true, reason: 'inventory_not_applicable' };
  }

  const marketplace = isMarketplaceCheckout(input.metadata);
  const { data: claim, error: claimErr } = await admin.rpc('claim_inventory_consume', {
    p_reference: reference,
    p_merchant_id: input.merchantId,
    p_transaction_id: input.transactionId,
    p_marketplace: marketplace,
  });
  if (claimErr) {
    console.error('claim_inventory_consume', reference, claimErr.message);
    return { ok: false, reason: claimErr.message };
  }
  const claimRow = (claim ?? {}) as { ok?: boolean; claimed?: boolean; skipped?: boolean };
  if (claimRow.skipped || claimRow.claimed === false) {
    return { ok: true, skipped: true, reason: 'already_claimed' };
  }

  await finalizePaymentLineItems(admin, {
    reference,
    metadata: input.metadata,
    paymentSessionId: input.paymentSessionId ?? null,
    applyInventory: true,
  });

  const { count: movementCount } = await admin
    .from('stock_movements')
    .select('id', { count: 'exact', head: true })
    .eq('reason', `sale:${reference}`);
  const linesApplied = movementCount ?? 0;

  await admin.rpc('complete_inventory_consume_claim', {
    p_reference: reference,
    p_lines_applied: linesApplied,
  });

  if (linesApplied > 0) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'inventory.consumed',
      actorType: 'system',
      customerEmail: input.buyerEmail ?? null,
      reference,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
      source: 'inventory.consume.requested',
      idempotencyKey: `inventory.consumed:${reference}`,
      payload: {
        fact_type: 'inventory.consumed',
        correlation_id: input.correlationId ?? null,
        causation_id: input.causationId ?? null,
        transaction_id: input.transactionId,
        marketplace,
        movements: linesApplied,
        // Underscore form kept in payload for dashboards that still filter inventory_consumed.
        legacy_event_type: 'inventory_consumed',
      },
    });
  }

  return { ok: true, linesApplied };
}

/** Emit request fact, then run Inventory Consumer (sync dispatch until Kernel v2). */
export async function requestAndConsumeInventory(
  admin: SupabaseClient,
  input: InventoryConsumeInput,
): Promise<{ ok: boolean; skipped?: boolean; reason?: string; linesApplied?: number }> {
  if (shouldSkipInventoryForPayment(input.metadata)) {
    return { ok: true, skipped: true, reason: 'inventory_not_applicable' };
  }

  await emitMerchantBusinessEvent(admin, {
    merchantId: input.merchantId,
    eventType: 'inventory.consume.requested',
    actorType: 'system',
    customerEmail: input.buyerEmail ?? null,
    reference: input.reference,
    amount: input.amount ?? null,
    currency: input.currency ?? null,
    source: 'payment.recorded',
    idempotencyKey: `inventory.consume.requested:${input.reference}`,
    payload: {
      fact_type: 'inventory.consume.requested',
      correlation_id: input.correlationId ?? null,
      causation_id: input.causationId ?? null,
      transaction_id: input.transactionId,
      marketplace: isMarketplaceCheckout(input.metadata),
      payment_session_id: input.paymentSessionId ?? null,
    },
  });

  return consumeInventoryConsumeRequested(admin, {
    ...input,
    causationId: input.causationId ?? `inventory.consume.requested:${input.reference}`,
  });
}

// RedFace Pay — bank verification + checkout verify (server-side only).
//
// IMPORTANT: the Paystack SECRET key must NEVER reach the browser. Set it as a
// Supabase Edge Function secret and read it here:
//
//   supabase secrets set PAYSTACK_SECRET_KEY=sk_live_xxx   (use a freshly rotated key)
//
// Checkout verify goes through PaymentProvider (Paystack adapter today).
// Bank list/resolve/validate remain Paystack-specific until Phase 4.

import { getPaymentProvider, verifyResultToLegacyEnvelope } from '../_shared/paymentProvider/index.ts';

const PAYSTACK_BASE = 'https://api.paystack.co';

function secret(): string {
  const key = Deno.env.get('PAYSTACK_SECRET_KEY');
  if (!key) throw new Error('PAYSTACK_SECRET_KEY is not configured');
  return key;
}

async function paystackGet(path: string) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    headers: { Authorization: `Bearer ${secret()}` },
  });
  return await res.json();
}

/** Verify a checkout reference via the active PaymentProvider (Paystack today). */
export async function verifyPaystackTransaction(reference: string) {
  const result = await getPaymentProvider().verifyTransaction(reference);
  return verifyResultToLegacyEnvelope(result);
}

async function paystackPost(path: string, body: unknown) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${secret()}`, 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  return await res.json();
}

function friendlyPaystackBankError(message: string): string {
  const m = message.trim();
  if (/insufficient balance/i.test(m)) {
    return 'Paystack account balance is too low for bank validation. Top up your Paystack balance in the Paystack Dashboard, or ask an admin to verify the bank account manually.';
  }
  return m || 'Bank verification failed';
}

function wrapPaystackBankResult(result: Record<string, unknown>) {
  if (result?.status === false) {
    const msg = friendlyPaystackBankError(String(result.message ?? ''));
    return { status: false, message: msg, paystack: result };
  }
  return result;
}

// GET /bank — list banks for a currency. For ZAR account validation, pass
// enabled_for_verification=true to get only banks that support validation.
export async function listBanks(payload: { currency?: string; enabled_for_verification?: boolean }) {
  const params = new URLSearchParams();
  params.set('currency', payload.currency || 'ZAR');
  if (payload.enabled_for_verification) params.set('enabled_for_verification', 'true');
  params.set('perPage', '100');
  return await paystackGet(`/bank?${params.toString()}`);
}

// GET /bank/resolve — Nigeria & Ghana: confirm a personal bank account.
export async function resolveAccount(payload: { account_number?: string; bank_code?: string }) {
  const params = new URLSearchParams();
  params.set('account_number', payload.account_number || '');
  params.set('bank_code', payload.bank_code || '');
  return wrapPaystackBankResult(await paystackGet(`/bank/resolve?${params.toString()}`) as Record<string, unknown>);
}

// POST /bank/validate — South Africa: validate personal/business accounts.
export async function validateAccount(payload: {
  account_name?: string;
  account_number?: string;
  account_type?: string;       // personal | business
  bank_code?: string;
  country_code?: string;       // e.g. ZA
  document_type?: string;      // identityNumber | passportNumber | businessRegistrationNumber
  document_number?: string;
}) {
  return wrapPaystackBankResult(await paystackPost('/bank/validate', {
    account_name: payload.account_name,
    account_number: payload.account_number,
    account_type: payload.account_type,
    bank_code: payload.bank_code,
    country_code: payload.country_code,
    document_type: payload.document_type,
    document_number: payload.document_number,
  }) as Record<string, unknown>);
}

/*
WIRING — add these cases to your existing `redface-pay` switch on `action`,
keeping your current CORS handling and the same JSON response shape you already
use for init_payment/confirm_payment:

  import { listBanks, resolveAccount, validateAccount } from './account-verification.ts';

  // inside your serve() handler, after parsing `const { action, ...body } = await req.json();`
  switch (action) {
    // ...your existing cases (create_subaccount, init_payment, confirm_payment)...

    case 'list_banks':
      return json(await listBanks(body));

    case 'resolve_account':
      return json(await resolveAccount(body));

    case 'validate_account':
      return json(await validateAccount(body));
  }

where `json(x)` is your existing helper that returns `new Response(JSON.stringify(x), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } })`.
*/

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type CryptoAsset = 'btc' | 'eth' | 'usdt_trc20' | 'usdt_erc20';

export const CRYPTO_ASSETS: Record<
  CryptoAsset,
  { coingeckoId: string; label: string; decimals: number; network: string }
> = {
  btc: { coingeckoId: 'bitcoin', label: 'Bitcoin (BTC)', decimals: 8, network: 'Bitcoin' },
  eth: { coingeckoId: 'ethereum', label: 'Ethereum (ETH)', decimals: 6, network: 'Ethereum' },
  usdt_trc20: { coingeckoId: 'tether', label: 'USDT (TRC-20)', decimals: 2, network: 'TRON' },
  usdt_erc20: { coingeckoId: 'tether', label: 'USDT (ERC-20)', decimals: 2, network: 'Ethereum' },
};

type CryptoSettingsRow = {
  merchant_id: string;
  enabled: boolean;
  btc_address: string | null;
  eth_address: string | null;
  usdt_trc20_address: string | null;
  usdt_erc20_address: string | null;
  default_asset: CryptoAsset;
  instructions: string | null;
};

export function walletForAsset(settings: CryptoSettingsRow, asset: CryptoAsset): string | null {
  const map: Record<CryptoAsset, string | null> = {
    btc: settings.btc_address,
    eth: settings.eth_address,
    usdt_trc20: settings.usdt_trc20_address,
    usdt_erc20: settings.usdt_erc20_address,
  };
  const addr = map[asset];
  return addr && addr.trim() ? addr.trim() : null;
}

export async function fetchCryptoFiatRate(asset: CryptoAsset, fiat: string): Promise<number | null> {
  const meta = CRYPTO_ASSETS[asset];
  if (!meta) return null;
  const vs = fiat.toLowerCase() === 'zar' ? 'zar' : fiat.toLowerCase();
  const url = `https://api.coingecko.com/api/v3/simple/price?ids=${meta.coingeckoId}&vs_currencies=${vs}`;
  const res = await fetch(url, { headers: { Accept: 'application/json' } });
  if (!res.ok) return null;
  const data = await res.json() as Record<string, Record<string, number>>;
  const rate = data[meta.coingeckoId]?.[vs];
  return typeof rate === 'number' && rate > 0 ? rate : null;
}

export function roundCryptoAmount(amount: number, decimals: number): number {
  const factor = 10 ** decimals;
  return Math.ceil(amount * factor) / factor;
}

export async function createCryptoPaymentRequest(
  admin: SupabaseClient,
  input: {
    merchantId: string;
    fiatAmount: number;
    fiatCurrency: string;
    asset: CryptoAsset;
    customerEmail?: string | null;
    customerNote?: string | null;
    paymentSessionId?: string | null;
    ttlMinutes?: number;
  },
): Promise<{ ok: true; request: Record<string, unknown> } | { ok: false; message: string }> {
  const { data: settings, error: settingsErr } = await admin
    .from('merchant_crypto_settings')
    .select('*')
    .eq('merchant_id', input.merchantId)
    .maybeSingle();

  if (settingsErr || !settings?.enabled) {
    return { ok: false, message: 'Crypto payments are not enabled for this merchant.' };
  }

  const asset = input.asset in CRYPTO_ASSETS ? input.asset : (settings.default_asset as CryptoAsset);
  const wallet = walletForAsset(settings as CryptoSettingsRow, asset);
  if (!wallet) {
    return { ok: false, message: `No wallet address configured for ${CRYPTO_ASSETS[asset].label}.` };
  }

  const fiatAmount = Math.round(Number(input.fiatAmount) * 100) / 100;
  if (!Number.isFinite(fiatAmount) || fiatAmount <= 0) {
    return { ok: false, message: 'Enter a valid amount.' };
  }

  const fiatCurrency = String(input.fiatCurrency || 'ZAR').toUpperCase();
  const rate = await fetchCryptoFiatRate(asset, fiatCurrency);
  if (!rate) {
    return { ok: false, message: 'Could not fetch live crypto rate. Try again in a moment.' };
  }

  const cryptoAmount = roundCryptoAmount(fiatAmount / rate, CRYPTO_ASSETS[asset].decimals);
  const reference = `RFC-${input.merchantId.slice(0, 4).toUpperCase()}-${crypto.randomUUID().slice(0, 8).toUpperCase()}`;
  const ttl = Math.min(Math.max(Number(input.ttlMinutes) || 60, 15), 24 * 60);
  const expiresAt = new Date(Date.now() + ttl * 60_000).toISOString();

  const { data: row, error } = await admin
    .from('crypto_payment_requests')
    .insert({
      merchant_id: input.merchantId,
      reference,
      fiat_amount: fiatAmount,
      fiat_currency: fiatCurrency,
      asset,
      crypto_amount: cryptoAmount,
      crypto_rate: rate,
      wallet_address: wallet,
      customer_email: input.customerEmail?.trim() || null,
      customer_note: input.customerNote?.trim() || null,
      payment_session_id: input.paymentSessionId || null,
      expires_at: expiresAt,
    })
    .select('*')
    .single();

  if (error || !row) {
    return { ok: false, message: error?.message || 'Could not create crypto payment request.' };
  }

  await admin.rpc('track_merchant_business_event', {
    p_merchant_id: input.merchantId,
    p_event_type: 'crypto_payment_requested',
    p_amount: fiatAmount,
    p_currency: fiatCurrency,
    p_session_id: reference,
    p_source: 'crypto',
    p_idempotency_key: `crypto_req:${reference}`,
    p_payload: { asset, crypto_amount: cryptoAmount, wallet_address: wallet },
  });

  return { ok: true, request: row as Record<string, unknown> };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

const SKIP_PURCHASE_TYPES = new Set([
  'plan_subscription',
  'product_subscription',
  'domain',
  'domain_renewal',
]);

export function normalizePhone(phone: string | null | undefined): string {
  return String(phone ?? '').replace(/\D/g, '');
}

export function generateOrderNumber(): string {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let s = 'RF-';
  for (let i = 0; i < 6; i++) {
    s += chars[Math.floor(Math.random() * chars.length)];
  }
  return s;
}

export type CreateOrderInput = {
  reference: string;
  merchantId: string;
  amount: number;
  currency: string | null;
  buyerEmail: string;
  buyerPhone?: string | null;
  productId?: string | null;
  productName?: string | null;
  label?: string | null;
  invoiceId?: string | null;
  purchaseType?: string | null;
  cartItemsJson?: string | null;
  marketplaceCheckoutId?: string | null;
};

type CartLine = { product_id: string; name: string; price: number; quantity: number };

function parseCartLines(json: string | null | undefined): CartLine[] {
  if (!json) return [];
  try {
    const parsed = JSON.parse(json);
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((row) => ({
        product_id: String(row.product_id ?? ''),
        name: String(row.name ?? 'Item'),
        price: Number(row.price) || 0,
        quantity: Math.max(1, Number(row.quantity) || 1),
      }))
      .filter((l) => l.product_id);
  } catch {
    return [];
  }
}

export async function createOrderFromPayment(
  admin: SupabaseClient,
  input: CreateOrderInput,
): Promise<{ ok: boolean; order_number?: string; skipped?: boolean; message?: string }> {
  const purchaseType = String(input.purchaseType ?? '').trim();
  if (SKIP_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: false, skipped: true };
  }
  if (!input.reference || !input.merchantId || !input.buyerEmail) {
    return { ok: false, message: 'missing required fields' };
  }

  const { data: existing } = input.marketplaceCheckoutId
    ? await admin
      .from('buyer_orders')
      .select('id, order_number')
      .eq('marketplace_checkout_id', input.marketplaceCheckoutId)
      .eq('merchant_id', input.merchantId)
      .maybeSingle()
    : await admin
      .from('buyer_orders')
      .select('id, order_number')
      .eq('reference', input.reference)
      .maybeSingle();
  if (existing?.order_number) {
    return { ok: true, order_number: existing.order_number };
  }

  const { data: txn } = await admin
    .from('transactions')
    .select('id, buyer_phone')
    .eq('reference', input.reference)
    .maybeSingle();

  let productName = String(input.productName || input.label || '').trim();
  const cartLines = parseCartLines(input.cartItemsJson);
  if (cartLines.length > 0) {
    if (cartLines.length === 1) {
      const line = cartLines[0];
      productName = line.quantity > 1 ? `${line.name} × ${line.quantity}` : line.name;
    } else {
      const units = cartLines.reduce((n, l) => n + l.quantity, 0);
      productName = `${cartLines.length} items (${units} units)`;
    }
  } else if (!productName && input.productId) {
    const { data: product } = await admin
      .from('products')
      .select('name')
      .eq('id', input.productId)
      .maybeSingle();
    productName = String(product?.name ?? '').trim();
  }
  if (!productName) productName = 'Order';

  const phone = normalizePhone(input.buyerPhone || (txn?.buyer_phone as string | null));

  let orderNumber = '';
  for (let attempt = 0; attempt < 8; attempt++) {
    orderNumber = generateOrderNumber();
    const { data: clash } = await admin
      .from('buyer_orders')
      .select('id')
      .eq('order_number', orderNumber)
      .maybeSingle();
    if (!clash) break;
    if (attempt === 7) return { ok: false, message: 'could not allocate order number' };
  }

  const totalQty = cartLines.length
    ? cartLines.reduce((n, l) => n + l.quantity, 0)
    : 1;
  const primaryProductId = cartLines.length === 1
    ? cartLines[0].product_id
    : (input.productId || null);

  const { data: order, error } = await admin
    .from('buyer_orders')
    .insert({
      order_number: orderNumber,
      merchant_id: input.merchantId,
      transaction_id: txn?.id ?? null,
      reference: input.reference,
      buyer_email: input.buyerEmail.toLowerCase().trim(),
      buyer_phone: phone || null,
      product_id: primaryProductId,
      product_name: productName,
      amount: input.amount,
      currency: input.currency || 'ZAR',
      status: 'confirmed',
      invoice_id: input.invoiceId || null,
      quantity: totalQty,
      marketplace_checkout_id: input.marketplaceCheckoutId || null,
      meta: cartLines.length ? { line_items: cartLines } : {},
    })
    .select('id, order_number')
    .single();

  if (error || !order) {
    return { ok: false, message: error?.message || 'order insert failed' };
  }

  await admin.from('buyer_order_events').insert({
    order_id: order.id,
    status: 'confirmed',
    note: 'Payment received — order created',
    actor: 'system',
  });

  return { ok: true, order_number: order.order_number };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { normalizeStudioPlanId } from './studioBilling.ts';

type BillingPatch = {
  status: string;
  downgradePlan: boolean;
  expiresAt: string | null;
  setExpires: boolean;
  clearExpires: boolean;
};

export function resolveStudioWebhookBillingPatch(
  eventType: string,
  data: Record<string, unknown>,
): BillingPatch | null {
  const nextPayRaw =
    data?.next_payment_date ||
    (data?.subscription as Record<string, unknown> | undefined)?.next_payment_date ||
    null;
  const nextPayMs = nextPayRaw ? Date.parse(String(nextPayRaw)) : NaN;
  const periodEndIso =
    Number.isFinite(nextPayMs) && nextPayMs > 0 ? new Date(nextPayMs).toISOString() : null;

  switch (eventType) {
    case 'charge.success':
    case 'subscription.create':
      return {
        status: 'active',
        downgradePlan: false,
        expiresAt: null,
        setExpires: true,
        clearExpires: true,
      };
    case 'subscription.disable':
    case 'subscription.not_renew': {
      if (periodEndIso && nextPayMs > Date.now()) {
        return {
          status: 'active',
          downgradePlan: false,
          expiresAt: periodEndIso,
          setExpires: true,
          clearExpires: false,
        };
      }
      return {
        status: 'cancelled',
        downgradePlan: true,
        expiresAt: new Date().toISOString(),
        setExpires: true,
        clearExpires: false,
      };
    }
    case 'invoice.payment_failed':
      return {
        status: 'attention',
        downgradePlan: false,
        expiresAt: new Date(Date.now() + 7 * 86_400_000).toISOString(),
        setExpires: true,
        clearExpires: false,
      };
    default:
      return null;
  }
}

function resolveStudioPlanFromData(data: Record<string, unknown>): {
  planId: string;
  interval: 'monthly' | 'yearly';
} | null {
  const meta = (data.metadata ?? {}) as Record<string, unknown>;
  const fromMeta = String(
    meta.internalPlanId ?? meta.internal_plan_id ?? meta.plan_id ?? '',
  ).trim();
  if (fromMeta) {
    const planId = normalizeStudioPlanId(fromMeta) ?? fromMeta;
    const interval = meta.interval === 'yearly' ? 'yearly' : 'monthly';
    return { planId, interval };
  }
  return null;
}

export function isStudioPaystackMetadata(metadata: Record<string, unknown>): boolean {
  const pt = String(metadata.purchase_type ?? '');
  const app = String(metadata.app ?? '');
  return pt === 'studio_subscription' || app === 'studio';
}

/** Apply Paystack webhook side effects to billing_accounts + platform ledger. */
export async function applyStudioBillingWebhook(
  admin: SupabaseClient,
  eventType: string,
  data: Record<string, unknown>,
): Promise<{ handled: boolean; reason?: string }> {
  const metadata = (data.metadata ?? {}) as Record<string, unknown>;
  if (!isStudioPaystackMetadata(metadata)) {
    return { handled: false, reason: 'not_studio' };
  }

  const lifecycle = resolveStudioWebhookBillingPatch(eventType, data);
  if (!lifecycle) return { handled: false, reason: 'ignored_event' };

  const customer = (data.customer ?? {}) as Record<string, unknown>;
  const email = String(customer.email ?? customer.customer_email ?? data.email ?? '').toLowerCase();
  const userId = String(metadata.user_id ?? metadata.userId ?? '').trim() || null;
  const resolved = resolveStudioPlanFromData(data);
  const interval = resolved?.interval ?? (metadata.interval === 'yearly' ? 'yearly' : 'monthly');
  const isActivation = eventType === 'charge.success' || eventType === 'subscription.create';
  const incomingPlan = resolved?.planId || (isActivation ? '' : 'free');

  const { error } = await admin.rpc('upsert_billing_account', {
    p_user_id: userId,
    p_email: email || 'unknown@paystack.webhook',
    p_plan_id: lifecycle.downgradePlan ? 'free' : incomingPlan,
    p_interval: interval,
    p_status: lifecycle.status,
    p_customer_code: customer.customer_code ?? customer.code ?? null,
    p_subscription_code: data.subscription_code
      ?? (data.subscription as Record<string, unknown> | undefined)?.subscription_code
      ?? null,
    p_last_reference: data.reference ?? null,
    p_next_payment_at: data.next_payment_date
      ?? (data.subscription as Record<string, unknown> | undefined)?.next_payment_date
      ?? null,
    p_metadata: { webhookEvent: eventType, paystackId: data.id, app: 'studio' },
    p_expires_at: lifecycle.clearExpires ? null : lifecycle.expiresAt,
    p_set_expires: lifecycle.setExpires,
    p_downgrade_plan: lifecycle.downgradePlan,
  });
  if (error) {
    console.error('studio webhook upsert_billing_account', error.message);
    throw error;
  }

  let syncUserId = userId;
  if (!syncUserId && email) {
    const { data: acct } = await admin
      .from('billing_accounts')
      .select('user_id')
      .ilike('customer_email', email)
      .maybeSingle();
    syncUserId = acct?.user_id ?? null;
  }
  if (syncUserId) {
    const { error: syncErr } = await admin.rpc('sync_studio_entitlement_to_ledger', {
      p_user_id: syncUserId,
    });
    if (syncErr) console.error('sync_studio_entitlement_to_ledger', syncErr.message);
  }

  return { handled: true };
}

