/** Resolve marketplace cart lines grouped by merchant (multi-vendor checkout). */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { feePlanFromMerchant } from './feePlan.ts';
import { type CartLine, cartLabel } from './cartItems.ts';

export type VendorCartBucket = {
  merchantId: string;
  businessName: string;
  paystackSubaccount: string;
  merchantPlan: string | null;
  platformFeePercent: number | null;
  platformFeeCap: number | null;
  items: CartLine[];
  subtotal: number;
};

export async function resolveMultiVendorCart(
  admin: SupabaseClient,
  cartItems: unknown,
): Promise<{ vendors: VendorCartBucket[]; total: number; currency: string } | { error: string }> {
  const raw = Array.isArray(cartItems) ? cartItems : [];
  if (!raw.length) return { error: 'cart_items is empty' };

  type PendingLine = { productId: string; variantId: string | null; qty: number };
  const pending: PendingLine[] = [];
  for (const row of raw) {
    const rec = row as Record<string, unknown>;
    const productId = String(rec.product_id ?? '').trim();
    const variantId = String(rec.variant_id ?? rec.variantId ?? '').trim() || null;
    const qty = Math.max(1, Math.min(99, Number(rec.quantity ?? rec.qty) || 1));
    if (!productId) return { error: 'cart item missing product_id' };
    pending.push({ productId, variantId, qty });
  }

  const productIds = [...new Set(pending.map((p) => p.productId))];
  const { data: products, error: prodErr } = await admin
    .from('products')
    .select('id, name, price, merchant_id, billing_type, track_inventory, stock_quantity, currency')
    .in('id', productIds);
  if (prodErr) return { error: prodErr.message || 'Could not load products' };

  const productMap = new Map((products ?? []).map((p) => [p.id as string, p]));
  const merchantIds = [...new Set((products ?? []).map((p) => p.merchant_id as string))];

  const { data: merchants, error: merchErr } = await admin
    .from('merchants')
    .select('id, business_name, status, paystack_subaccount, paystack_split_code, merchant_plan, subscription_status, platform_fee_percent, platform_fee_cap')
    .in('id', merchantIds);
  if (merchErr) return { error: merchErr.message || 'Could not load merchants' };

  const merchantMap = new Map((merchants ?? []).map((m) => [m.id as string, m]));
  const buckets = new Map<string, VendorCartBucket>();
  let currency = 'ZAR';

  for (const line of pending) {
    const p = productMap.get(line.productId);
    if (!p) return { error: 'A product in your cart is no longer available' };
    if (p.billing_type === 'subscription') {
      return { error: 'Subscription products must be purchased separately' };
    }

    const merchantId = String(p.merchant_id);
    const merchant = merchantMap.get(merchantId);
    if (!merchant || merchant.status !== 'approved') {
      return { error: 'A seller in your cart is not available for checkout' };
    }

    const routeCode = String(merchant.paystack_split_code || merchant.paystack_subaccount || '').trim();
    if (!routeCode.startsWith('ACCT_') && !routeCode.startsWith('SPL_')) {
      return { error: `${merchant.business_name} is not ready to receive marketplace payments yet` };
    }
    if (routeCode.startsWith('SPL_')) {
      return { error: `${merchant.business_name} uses legacy split routing — contact support for multi-seller checkout` };
    }

    let unitPrice = Number(p.price);
    let variantLabel: string | null = null;
    if (line.variantId) {
      const { data: variant } = await admin
        .from('product_variants')
        .select('id, label, price, stock_quantity, active')
        .eq('id', line.variantId)
        .eq('product_id', line.productId)
        .maybeSingle();
      if (!variant || !variant.active) return { error: 'A selected size/variant is no longer available' };
      unitPrice = Number(variant.price ?? p.price);
      variantLabel = variant.label;
      if (variant.stock_quantity != null && Number(variant.stock_quantity) < line.qty) {
        return { error: `${p.name} (${variant.label}) is out of stock` };
      }
    } else if (p.track_inventory && Number(p.stock_quantity || 0) < line.qty) {
      return { error: `${p.name} is out of stock` };
    }

    currency = String(p.currency || currency || 'ZAR');

    if (!buckets.has(merchantId)) {
      buckets.set(merchantId, {
        merchantId,
        businessName: String(merchant.business_name ?? 'Seller'),
        paystackSubaccount: routeCode,
        merchantPlan: feePlanFromMerchant(merchant),
        platformFeePercent: merchant.platform_fee_percent != null ? Number(merchant.platform_fee_percent) : null,
        platformFeeCap: merchant.platform_fee_cap != null ? Number(merchant.platform_fee_cap) : null,
        items: [],
        subtotal: 0,
      });
    }

    const bucket = buckets.get(merchantId)!;
    bucket.items.push({
      product_id: p.id as string,
      name: p.name as string,
      price: unitPrice,
      quantity: line.qty,
      ...(line.variantId ? { variant_id: line.variantId, variant_label: variantLabel ?? undefined } : {}),
    });
    bucket.subtotal += unitPrice * line.qty;
  }

  const vendors = [...buckets.values()];
  if (vendors.length < 2) {
    return { error: 'Multi-seller checkout requires items from at least two sellers' };
  }

  const total = vendors.reduce((n, v) => n + v.subtotal, 0);
  if (!(total > 0)) return { error: 'cart total must be greater than zero' };

  return { vendors, total, currency };
}

export function marketplaceCartLabel(vendors: VendorCartBucket[]): string {
  const lines = vendors.flatMap((v) => v.items);
  return cartLabel(lines);
}

/**
 * Business modules consume Business Facts — not provider APIs (Invariant XI).
 *
 * Called once per newly committed ledger payment (`payment.recorded`).
 * Inventory runs as its own bounded context:
 *   payment.recorded → inventory.consume.requested → inventory.consumed
 * CRM and loyalty remain direct consumers until they follow the same pattern.
 * POS cash/walk-in sales without payment.recorded stay on their own path.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import { completePosSplitCardTender, posSaleIdFromMetadata } from './posSplitTender.ts';
import {
  isMarketplaceCheckout,
  resolveCheckoutMetadata,
  shouldSkipInventoryForPayment,
} from './transactionLineItems.ts';
import { requestAndConsumeInventory } from './consumeInventoryFromPayment.ts';
import { consumeCrmFromPaymentRecorded } from './consumeCrmFromPayment.ts';
import { consumeLoyaltyFromPaymentRecorded } from './consumeLoyaltyFromPayment.ts';
import { consumeReviewLifecycleFromPaymentRecorded } from './consumeReviewLifecycleFromPayment.ts';

export type PaymentRecordedContext = {
  reference: string;
  merchantId?: string | null;
  amount?: number | null;
  currency?: string | null;
  businessIntent?: string | null;
  processingRail?: string | null;
  txnKey?: string | null;
  correlationId?: string | null;
  causationId?: string | null;
};

export async function consumePaymentRecorded(
  admin: SupabaseClient,
  ctx: PaymentRecordedContext,
): Promise<{ ok: boolean; skipped?: boolean; error?: string }> {
  const reference = String(ctx.reference ?? '').trim();
  if (!reference) return { ok: false, error: 'reference_required' };

  const { data: txn, error: txnErr } = await admin
    .from('transactions')
    .select('id, merchant_id, amount, currency, buyer_email, payment_session_id, status')
    .eq('reference', reference)
    .maybeSingle();
  if (txnErr || !txn) return { ok: false, error: txnErr?.message ?? 'transaction_not_found' };
  if (txn.status !== 'success') return { ok: true, skipped: true };

  let sessionMeta: Record<string, unknown> = {};
  let captureMethod: string | null = null;
  let businessIntent = ctx.businessIntent ?? null;

  if (txn.payment_session_id) {
    const { data: sess } = await admin
      .from('payment_sessions')
      .select('metadata, business_intent, capture_method, processing_rail')
      .eq('id', txn.payment_session_id)
      .maybeSingle();
    if (sess) {
      sessionMeta = (sess.metadata && typeof sess.metadata === 'object')
        ? sess.metadata as Record<string, unknown>
        : {};
      captureMethod = sess.capture_method ?? null;
      businessIntent = businessIntent ?? sess.business_intent ?? null;
    }
  }

  const posSaleId = posSaleIdFromMetadata(sessionMeta);
  const merchantId = String(ctx.merchantId ?? txn.merchant_id ?? '');
  if (!merchantId) return { ok: false, error: 'merchant_id_required' };

  if (posSaleId) {
    const splitDone = await completePosSplitCardTender(
      admin,
      posSaleId,
      reference,
      txn.id,
    );
    if (!splitDone.ok) {
      console.error('consumePaymentRecorded pos_card_tender', reference, posSaleId, splitDone.error);
      return { ok: false, error: splitDone.error ?? 'pos_card_tender_failed' };
    }

    await emitMerchantBusinessEvent(admin, {
      merchantId,
      eventType: 'pos_card_settled',
      actorType: 'system',
      customerEmail: txn.buyer_email ?? null,
      reference,
      amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
      currency: ctx.currency ?? txn.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `pos_card_settled:${reference}`,
      payload: {
        pos_sale_id: posSaleId,
        business_intent: businessIntent,
        capture_method: captureMethod,
        processing_rail: ctx.processingRail ?? null,
        txn_key: ctx.txnKey ?? null,
        transaction_id: txn.id,
      },
    });
  }

  const checkoutMeta = await resolveCheckoutMetadata(admin, {
    reference,
    paymentSessionId: txn.payment_session_id,
    sessionMeta,
  });

  if (!shouldSkipInventoryForPayment(checkoutMeta)) {
    const inv = await requestAndConsumeInventory(admin, {
      reference,
      merchantId,
      transactionId: txn.id,
      buyerEmail: txn.buyer_email,
      amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
      currency: ctx.currency ?? txn.currency ?? null,
      paymentSessionId: txn.payment_session_id,
      metadata: checkoutMeta,
      correlationId: ctx.correlationId ?? null,
      causationId: ctx.causationId ?? null,
    });
    if (!inv.ok) {
      console.error('consumePaymentRecorded inventory', reference, inv.reason);
    }
  }

  await consumeCrmFromPaymentRecorded(admin, {
    reference,
    merchantId,
    transactionId: txn.id,
    buyerEmail: txn.buyer_email,
    amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
    currency: ctx.currency ?? txn.currency ?? null,
    paymentSessionId: txn.payment_session_id,
    businessIntent: businessIntent ?? ctx.businessIntent ?? null,
    processingRail: ctx.processingRail ?? null,
    correlationId: ctx.correlationId ?? null,
    causationId: ctx.causationId ?? null,
  });

  // Multi-vendor marketplace loyalty stays in fan-out (per seller subtotal).
  if (!isMarketplaceCheckout(checkoutMeta)) {
    await consumeLoyaltyFromPaymentRecorded(admin, {
      reference,
      merchantId,
      buyerEmail: txn.buyer_email,
      amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
      currency: ctx.currency ?? txn.currency ?? null,
      paymentSessionId: txn.payment_session_id,
    });
  }

  const purchaseType = String(
    checkoutMeta.purchase_type ?? checkoutMeta.object_type ?? '',
  ).toLowerCase();
  await consumeReviewLifecycleFromPaymentRecorded(admin, {
    reference,
    merchantId,
    buyerEmail: txn.buyer_email,
    amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
    currency: ctx.currency ?? txn.currency ?? null,
    purchaseType,
    correlationId: ctx.correlationId ?? null,
    causationId: ctx.causationId ?? null,
  });

  return { ok: true };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { markAbandonedCartRecovered } from './abandonedCart.ts';
import { createOrderFromPayment } from './orderCreate.ts';
import { persistTransactionLineItems, type LineItemInput } from './transactionLineItems.ts';
import type { VendorCartBucket } from './resolveMultiVendorCart.ts';

export type MarketplacePricing = {
  plan: string;
  percent: number;
  cap: number | null;
  feeSub: number;
  feeMajor: number;
  merchantShareMajor: number;
  merchantShareSub: number;
};

export function computeVendorPricing(
  subtotalMajor: number,
  toSubunits: (n: number) => number,
  computePricing: (input: {
    amountSub: number;
    plan?: string | null;
    customPercent?: number | null;
    capMajor?: number | null;
  }) => { plan: string; percent: number; cap: number | null; feeSub: number },
  vendor: VendorCartBucket,
): MarketplacePricing {
  const amountSub = toSubunits(subtotalMajor);
  const pricing = computePricing({
    amountSub,
    plan: vendor.merchantPlan,
    customPercent: vendor.platformFeePercent,
    capMajor: vendor.platformFeeCap,
  });
  const merchantShareSub = Math.max(0, amountSub - pricing.feeSub);
  return {
    plan: pricing.plan,
    percent: pricing.percent,
    cap: pricing.cap,
    feeSub: pricing.feeSub,
    feeMajor: pricing.feeSub / 100,
    merchantShareMajor: merchantShareSub / 100,
    merchantShareSub,
  };
}

export function buildPaystackFlatSplit(
  vendors: Array<{ paystackSubaccount: string; merchantShareSub: number }>,
): Record<string, unknown> {
  return {
    type: 'flat',
    bearer_type: 'account',
    subaccounts: vendors.map((v) => ({
      subaccount: v.paystackSubaccount,
      share: v.merchantShareSub,
    })),
  };
}

export async function fanOutMarketplaceCheckoutSuccess(
  admin: SupabaseClient,
  input: {
    reference: string;
    buyerEmail: string;
    buyerPhone?: string | null;
    currency: string;
    parentTransactionId?: string | null;
  },
): Promise<{ ok: boolean; orderNumbers?: string[]; message?: string }> {
  const { data: checkout } = await admin
    .from('marketplace_checkouts')
    .select('id, status, buyer_email, currency, total_amount')
    .eq('reference', input.reference)
    .maybeSingle();

  if (!checkout?.id) return { ok: false, message: 'marketplace checkout not found' };

  if (checkout.status === 'paid') {
    const { data: existingOrders } = await admin
      .from('buyer_orders')
      .select('order_number')
      .eq('marketplace_checkout_id', checkout.id);
    return { ok: true, orderNumbers: (existingOrders ?? []).map((o) => o.order_number as string) };
  }

  const { data: vendorRows } = await admin
    .from('marketplace_checkout_vendors')
    .select('*')
    .eq('checkout_id', checkout.id)
    .order('created_at', { ascending: true });

  if (!vendorRows?.length) return { ok: false, message: 'no vendor rows' };

  const orderNumbers: string[] = [];

  for (const row of vendorRows) {
    const merchantId = String(row.merchant_id);
    const cartJson = JSON.stringify(row.cart_items_json ?? []);
    const items = (row.cart_items_json ?? []) as Array<{ name: string; quantity: number }>;
    const label = items.length === 1
      ? (items[0].quantity > 1 ? `${items[0].name} × ${items[0].quantity}` : items[0].name)
      : `${items.length} items`;

    const order = await createOrderFromPayment(admin, {
      reference: input.reference,
      merchantId,
      amount: Number(row.subtotal),
      currency: input.currency || checkout.currency || 'ZAR',
      buyerEmail: input.buyerEmail,
      buyerPhone: input.buyerPhone,
      label,
      purchaseType: 'marketplace_cart',
      cartItemsJson: cartJson,
      marketplaceCheckoutId: checkout.id,
    });

    if (order.ok && order.order_number) {
      orderNumbers.push(order.order_number);
      const { data: orderRow } = await admin
        .from('buyer_orders')
        .select('id')
        .eq('marketplace_checkout_id', checkout.id)
        .eq('merchant_id', merchantId)
        .maybeSingle();

      await admin.from('marketplace_checkout_vendors').update({
        buyer_order_id: orderRow?.id ?? null,
      }).eq('id', row.id);

      await admin.rpc('award_loyalty_points', {
        p_merchant_id: merchantId,
        p_buyer_email: input.buyerEmail.toLowerCase(),
        p_amount: Number(row.subtotal),
        p_reference: `${input.reference}:${merchantId}`,
      }).then(() => {}, () => {});

      await markAbandonedCartRecovered(admin, merchantId, input.buyerEmail);
    }
  }

  if (input.parentTransactionId) {
    const allLines: LineItemInput[] = [];
    for (const row of vendorRows) {
      const merchantId = String(row.merchant_id);
      const vendorLines = (row.cart_items_json as Array<Record<string, unknown>> ?? []).map((item, idx) => {
        const qty = Math.max(1, Number(item.quantity) || 1);
        const unit = Number(item.price) || 0;
        return {
          product_id: String(item.product_id ?? ''),
          name: String(item.name ?? 'Item'),
          quantity: qty,
          unit_price: unit,
          line_total: Math.round(unit * qty * 100) / 100,
          variant_label: item.variant_label ? String(item.variant_label) : null,
          meta: { sort_order: idx, marketplace_checkout_id: checkout.id, merchant_id: merchantId },
        };
      });
      allLines.push(...vendorLines);
    }
    // Line items + inventory are owned by payment.recorded → Inventory Consumer.
    // Fan-out only mirrors lines onto the parent txn when the consumer has not yet
    // (idempotent persist). Never call apply_inventory_from_transaction here.
    if (allLines.length) {
      await persistTransactionLineItems(admin, {
        transactionId: input.parentTransactionId,
        reference: input.reference,
        lines: allLines,
      });
    }
  }

  await admin.from('marketplace_checkouts').update({
    status: 'paid',
    updated_at: new Date().toISOString(),
  }).eq('id', checkout.id);

  await admin.rpc('try_qualify_founding_and_referrals', {
    p_merchant_id: vendorRows[0].merchant_id,
  }).then(() => {}, () => {});

  return { ok: true, orderNumbers };
}

/**
 * Payment Terminal abstraction — SoftPOS-ready.
 *
 * Doctrine: the UI must never know whether the merchant is using an NFC card,
 * SoftPOS phone, QR, payment link, or external reader. Every payment source
 * implements the same terminal contract. SoftPOS partners plug in by registering
 * a rail + flipping terminal.provider — business modules stay unchanged.
 *
 * @see docs/codex/platform/financial-abstraction-layer.md
 * @see docs/codex/platform/commerce-intelligence-engine-doctrine.md
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import type { CaptureMethod } from './paymentRouting.ts';

export type TerminalKind =
  | 'nfc_card'
  | 'softpos'
  | 'qr'
  | 'payment_link'
  | 'cash'
  | 'external_reader';

export type TerminalStatus = 'active' | 'inactive' | 'pending_onboarding';

/**
 * First-class payment terminal. NFC cards (payment_objects) are one kind;
 * SoftPOS phones, QR posters, and payment links are others.
 */
export type PaymentTerminal = {
  id: string;
  kind: TerminalKind;
  label: string;
  status: TerminalStatus;
  merchantId: string;
  /** Capture method this terminal asks the Routing Engine to settle. */
  captureMethod: CaptureMethod;
  /** SoftPOS / acquiring partner when kind requires one. */
  provider: string | null;
  tapCode: string | null;
  locationId: string | null;
  deviceRef: string | null;
  supportedMethods: string[];
  capabilities: string[];
};

export type PaymentObjectRow = {
  id: string;
  merchant_id: string;
  label: string | null;
  tap_code: string | null;
  medium: string | null;
  status: string | null;
  type: string | null;
  metadata?: Record<string, unknown> | null;
};

function metaString(meta: Record<string, unknown> | null | undefined, key: string): string | null {
  const v = meta?.[key];
  if (v == null) return null;
  const s = String(v).trim();
  return s || null;
}

/**
 * Map a payment_object row → PaymentTerminal.
 * SoftPOS objects carry metadata.terminal_kind = 'softpos' + metadata.provider.
 */
export function paymentObjectToTerminal(row: PaymentObjectRow): PaymentTerminal {
  const meta = row.metadata && typeof row.metadata === 'object' ? row.metadata : {};
  const kindRaw = metaString(meta, 'terminal_kind') ?? metaString(meta, 'kind');
  const medium = String(row.medium ?? '').toLowerCase();
  const provider = metaString(meta, 'provider') ?? metaString(meta, 'softpos_partner');

  let kind: TerminalKind = 'nfc_card';
  if (kindRaw === 'softpos' || medium === 'softpos') kind = 'softpos';
  else if (kindRaw === 'qr' || medium === 'qr') kind = 'qr';
  else if (kindRaw === 'external_reader' || medium === 'reader') kind = 'external_reader';
  else if (row.tap_code || medium === 'nfc' || medium === 'tag') kind = 'nfc_card';

  const captureMethod: CaptureMethod =
    kind === 'softpos'
      ? (provider === 'istore_tap' ? 'apple_tap' : 'softpos')
      : kind === 'qr'
        ? 'qr'
        : kind === 'external_reader'
          ? 'external_terminal'
          : 'nfc_tap';

  const status: TerminalStatus =
    row.status === 'active'
      ? (kind === 'softpos' && !provider ? 'pending_onboarding' : 'active')
      : row.status === 'pending'
        ? 'pending_onboarding'
        : 'inactive';

  return {
    id: String(row.id),
    kind,
    label: String(row.label ?? (kind === 'softpos' ? 'SoftPOS' : 'Terminal')),
    status,
    merchantId: String(row.merchant_id),
    captureMethod,
    provider,
    tapCode: row.tap_code ? String(row.tap_code) : null,
    locationId: metaString(meta, 'location_id'),
    deviceRef: metaString(meta, 'device_ref') ?? metaString(meta, 'device'),
    supportedMethods: kind === 'cash'
      ? ['cash']
      : kind === 'softpos'
        ? ['softpos', 'apple_tap', 'card_present']
        : ['nfc_tap', 'qr', 'payment_link'],
    capabilities: [
      'collect_payment',
      ...(kind === 'nfc_card' || kind === 'softpos' ? ['pos_terminal'] : []),
      ...(kind === 'softpos' ? ['softpos'] : []),
    ],
  };
}

/** Synthetic terminals that are not payment_objects (cash drawer, pay-by-link). */
export function syntheticTerminals(merchantId: string): PaymentTerminal[] {
  return [
    {
      id: `synthetic:cash:${merchantId}`,
      kind: 'cash',
      label: 'Cash',
      status: 'active',
      merchantId,
      captureMethod: 'cash',
      provider: null,
      tapCode: null,
      locationId: null,
      deviceRef: null,
      supportedMethods: ['cash'],
      capabilities: ['collect_payment', 'cash_register'],
    },
    {
      id: `synthetic:link:${merchantId}`,
      kind: 'payment_link',
      label: 'Payment link',
      status: 'active',
      merchantId,
      captureMethod: 'payment_link',
      provider: null,
      tapCode: null,
      locationId: null,
      deviceRef: null,
      supportedMethods: ['payment_link'],
      capabilities: ['collect_payment', 'share_link'],
    },
  ];
}

export async function listPaymentTerminals(
  admin: SupabaseClient,
  merchantId: string,
  opts?: { includeSynthetic?: boolean },
): Promise<PaymentTerminal[]> {
  let data: PaymentObjectRow[] | null = null;

  const withMeta = await admin
    .from('payment_objects')
    .select('id, merchant_id, label, tap_code, medium, status, type, metadata')
    .eq('merchant_id', merchantId)
    .eq('status', 'active')
    .order('created_at', { ascending: true })
    .limit(100);

  if (!withMeta.error) {
    data = (withMeta.data ?? []) as PaymentObjectRow[];
  } else {
    // metadata column may not exist until migration 0270
    const fallback = await admin
      .from('payment_objects')
      .select('id, merchant_id, label, tap_code, medium, status, type')
      .eq('merchant_id', merchantId)
      .eq('status', 'active')
      .order('created_at', { ascending: true })
      .limit(100);
    if (fallback.error) {
      return opts?.includeSynthetic === false ? [] : syntheticTerminals(merchantId);
    }
    data = (fallback.data ?? []) as PaymentObjectRow[];
  }

  const fromObjects = data.map((row) => paymentObjectToTerminal(row));

  if (opts?.includeSynthetic === false) return fromObjects;
  return [...fromObjects, ...syntheticTerminals(merchantId)];
}

export async function getPaymentTerminal(
  admin: SupabaseClient,
  merchantId: string,
  terminalId: string,
): Promise<PaymentTerminal | null> {
  if (terminalId.startsWith('synthetic:')) {
    return syntheticTerminals(merchantId).find((t) => t.id === terminalId) ?? null;
  }
  const { data } = await admin
    .from('payment_objects')
    .select('id, merchant_id, label, tap_code, medium, status, type, metadata')
    .eq('id', terminalId)
    .eq('merchant_id', merchantId)
    .maybeSingle();
  if (!data) return null;
  return paymentObjectToTerminal(data as PaymentObjectRow);
}

/** Capture method the Routing Engine should use for this terminal. */
export function terminalCaptureMethod(terminal: PaymentTerminal): CaptureMethod {
  return terminal.captureMethod;
}

// Point a registered domain at the RedFace storefront host (Vercel).

import { namecomFetch } from './namecomClient.ts';

const WWW_CNAME = Deno.env.get('STORE_DNS_WWW_CNAME') ?? 'cname.vercel-dns.com';
const APEX_A = Deno.env.get('STORE_DNS_APEX_A') ?? '76.76.21.21';

type DnsRecord = { id?: number; host?: string; type?: string; answer?: string; priority?: number };

export type DnsSpec = { host: string; type: string; answer: string; priority?: number };

function hostMatches(record: DnsRecord, host: string) {
  const h = record.host ?? '';
  if (host === '@') return h === '@' || h === '';
  return h === host;
}

export async function listDnsRecords(domainName: string): Promise<DnsRecord[]> {
  const res = await namecomFetch(`/domains/${encodeURIComponent(domainName)}/records`, { method: 'GET' });
  if (!res.ok) return [];
  return ((res.data as any)?.records ?? []) as DnsRecord[];
}

export async function deleteDnsRecord(domainName: string, recordId: number) {
  const res = await namecomFetch(
    `/domains/${encodeURIComponent(domainName)}/records/${recordId}`,
    { method: 'DELETE' },
  );
  if (!res.ok) return { ok: false, error: res.data };
  return { ok: true };
}

export async function getDomainInfo(domainName: string) {
  const res = await namecomFetch(`/domains/${encodeURIComponent(domainName)}`, { method: 'GET' });
  if (!res.ok) return { ok: false, data: res.data };
  const d = (res.data as any)?.domain ?? res.data ?? {};
  return {
    ok: true,
    domain: {
      domainName: d.domainName ?? domainName,
      nameservers: (d.nameservers ?? d.nameServers ?? []) as string[],
      expireDate: d.expireDate ?? null,
      autorenewEnabled: d.autorenewEnabled ?? null,
      privacyEnabled: d.privacyEnabled ?? null,
      locked: d.locked ?? null,
    },
  };
}

export async function setDomainNameservers(domainName: string, nameservers: string[]) {
  const cleaned = nameservers.map((n) => n.trim().toLowerCase()).filter(Boolean);
  if (!cleaned.length) return { ok: false, message: 'At least one nameserver is required.' };
  const res = await namecomFetch(`/domains/${encodeURIComponent(domainName)}:setNameservers`, {
    method: 'POST',
    body: JSON.stringify({ nameservers: cleaned }),
  });
  if (!res.ok) {
    return { ok: false, message: (res.data as any)?.message || 'Could not update nameservers' };
  }
  return { ok: true, domain: (res.data as any)?.domain ?? res.data };
}

const DEFAULT_NAMECOM_NS = ['ns1.name.com', 'ns2.name.com', 'ns3.name.com', 'ns4.name.com'];

export async function useDefaultNameservers(domainName: string) {
  return setDomainNameservers(domainName, DEFAULT_NAMECOM_NS);
}

export { DEFAULT_NAMECOM_NS };

export async function upsertDnsRecord(domainName: string, existing: DnsRecord[], spec: DnsSpec) {
  const match = existing.find((r) => hostMatches(r, spec.host) && r.type === spec.type && (spec.type !== 'MX' || r.answer === spec.answer));
  const body: Record<string, unknown> = { host: spec.host, type: spec.type, answer: spec.answer, ttl: 300 };
  if (spec.priority != null) body.priority = spec.priority;

  if (match?.id) {
    if (match.answer === spec.answer && (spec.priority == null || match.priority === spec.priority)) {
      return { ok: true, record: match, action: 'skipped' as const };
    }
    const res = await namecomFetch(
      `/domains/${encodeURIComponent(domainName)}/records/${match.id}`,
      { method: 'PUT', body: JSON.stringify(body) },
    );
    if (!res.ok) return { ok: false, error: res.data, action: 'update' as const };
    return { ok: true, record: res.data, action: 'updated' as const };
  }

  const res = await namecomFetch(
    `/domains/${encodeURIComponent(domainName)}/records`,
    { method: 'POST', body: JSON.stringify(body) },
  );
  if (!res.ok) return { ok: false, error: res.data, action: 'create' as const };
  return { ok: true, record: res.data, action: 'created' as const };
}

async function listRecords(domainName: string): Promise<DnsRecord[]> {
  return listDnsRecords(domainName);
}

async function upsertRecord(domainName: string, existing: DnsRecord[], spec: DnsSpec) {
  return upsertDnsRecord(domainName, existing, spec);
}

export async function setupStoreDns(domainName: string): Promise<{
  ok: boolean;
  message?: string;
  target?: string;
  records?: unknown[];
}> {
  const name = domainName.trim().toLowerCase();
  if (!name) return { ok: false, message: 'domainName required' };

  const existing = await listRecords(name);
  const specs = [
    { host: 'www', type: 'CNAME', answer: WWW_CNAME },
    { host: '@', type: 'A', answer: APEX_A },
  ];

  const results: unknown[] = [];
  for (const spec of specs) {
    const result = await upsertRecord(name, existing, spec);
    if (!result.ok) {
      return {
        ok: false,
        message: (result.error as any)?.message || `DNS ${result.action} failed for ${spec.host}`,
        records: results,
      };
    }
    if (result.record) results.push(result.record);
  }

  return {
    ok: true,
    target: WWW_CNAME,
    records: results,
    message: 'Store DNS configured — allow up to 24h for propagation.',
  };
}

export function storeDnsTargets() {
  return { wwwCname: WWW_CNAME, apexA: APEX_A };
}

/** Point a Name.com domain at an InstaWP site hostname (Website Cloud). */
export async function setupWebsiteCloudDns(
  domainName: string,
  instawpHostname: string,
): Promise<{
  ok: boolean;
  message?: string;
  target?: string;
  records?: unknown[];
  apex_manual?: boolean;
}> {
  const name = domainName.trim().toLowerCase();
  const target = instawpHostname.trim().toLowerCase().replace(/\.$/, '');
  if (!name || !target) return { ok: false, message: 'domainName and instawpHostname required' };

  // Never mutate DNS on the apex redfacepay.co.za zone from Website Cloud — breaks app/login.
  if (name === 'redfacepay.co.za' || name.endsWith('.redfacepay.co.za')) {
    return {
      ok: false,
      message:
        'redfacepay.co.za and its subdomains (app, www, developers) are platform infrastructure. Connect a domain you purchased for your business instead.',
    };
  }

  const existing = await listRecords(name);
  const wwwResult = await upsertRecord(name, existing, { host: 'www', type: 'CNAME', answer: target });
  if (!wwwResult.ok) {
    return {
      ok: false,
      message: (wwwResult.error as { message?: string })?.message || 'www CNAME failed',
      records: [],
    };
  }

  const apexResult = await upsertRecord(name, existing, { host: '@', type: 'CNAME', answer: target });
  const records: unknown[] = [];
  if (wwwResult.record) records.push(wwwResult.record);
  if (apexResult.ok && apexResult.record) records.push(apexResult.record);

  if (!apexResult.ok) {
    return {
      ok: true,
      target,
      records,
      apex_manual: true,
      message: `www → ${target} configured. Root (@) may need ANAME/ALIAS at your registrar — see InstaWP domain docs.`,
    };
  }

  return {
    ok: true,
    target,
    records,
    message: `Website Cloud DNS configured — allow up to 24h for propagation.`,
  };
}
